parameters.jsCode:
// Combine gap analysis and anomaly detection results
const webhookData = $('Webhook Trigger').first().json;

let gapAnalysis = {};
let anomalyDetection = {};

try {
  const gapText = $('Gemini - Gap Analysis').first().json.candidates[0].content.parts[0].text;
  gapAnalysis = JSON.parse(gapText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim());
} catch (e) {
  gapAnalysis = {
    overall_compliance_score: 0,
    gaps: [],
    met_requirements: [],
    partial_compliance: [],
    recommendations: ['Manual review required - automated analysis failed'],
    risk_assessment: { overall_risk_level: 'unknown', risk_factors: [] }
  };
}

try {
  const anomalyText = $('Gemini - Clause Anomaly Detection').first().json.candidates[0].content.parts[0].text;
  anomalyDetection = JSON.parse(anomalyText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim());
} catch (e) {
  anomalyDetection = {
    anomalies: [],
    unusual_terms: [],
    missing_standard_clauses: [],
    overall_anomaly_score: 0
  };
}

// Compute combined compliance score
const complianceScore = gapAnalysis.overall_compliance_score || 0;
const anomalyPenalty = (anomalyDetection.overall_anomaly_score || 0) * 15;
const adjustedScore = Math.max(0, Math.min(100, complianceScore - anomalyPenalty));

return [{
  json: {
    document_id: webhookData.document_id,
    entity_id: webhookData.entity_id,
    compliance_score: adjustedScore,
    gap_analysis: gapAnalysis,
    anomaly_detection: anomalyDetection,
    gap_count: (gapAnalysis.gaps || []).length,
    anomaly_count: (anomalyDetection.anomalies || []).length,
    risk_level: adjustedScore >= 80 ? 'low' : adjustedScore >= 60 ? 'medium' : adjustedScore >= 40 ? 'high' : 'critical',
    evaluated_at: new Date().toISOString()
  }
}];
